const fs = require('fs');
const path = require('path');

class ProblemsService {
  static async detail(problemId) {
    const problemsPath = path.resolve(__dirname, '../../data/problems.json');
    let problemsData;
    try {
      const rawData = await fs.promises.readFile(problemsPath, 'utf-8');
      problemsData = JSON.parse(rawData);
    } catch (err) {
      throw new Error('Failed to load problems data');
    }

    const problem = problemsData.find(p => p.problemId === problemId);
    if (!problem) {
      const error = new Error(`Problem with id ${problemId} not found`);
      error.status = 404;
      error.json = { message: `Problem with id ${problemId} not found` };
      throw error;
    }

    // Aggregate component statistics
    const componentStats = {
      languages: {},
      statusCounts: {},
      maxPoints: 0,
    };

    if (Array.isArray(problem.components)) {
      for (const comp of problem.components) {
        // Aggregate languages counts
        if (comp.language) {
          componentStats.languages[comp.language] = (componentStats.languages[comp.language] || 0) + 1;
        }
        // Aggregate status counts
        if (comp.status) {
          componentStats.statusCounts[comp.status] = (componentStats.statusCounts[comp.status] || 0) + 1;
        }
        // Track max points
        if (typeof comp.points === 'number' && comp.points > componentStats.maxPoints) {
          componentStats.maxPoints = comp.points;
        }
      }
    }

    return {
      ...problem,
      componentStats,
    };
  }
}

module.exports = ProblemsService;
